CREATE TRIGGER [dbo].[InventoryItem_History]ON [dbo].[InventoryItem]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.InventoryItemId IS NOT NULL AND d.InventoryItemId IS NULL THEN 'I' 		WHEN i.InventoryItemId IS NOT NULL AND d.InventoryItemId IS NOT NULL THEN 'U' 		WHEN i.InventoryItemId IS NULL AND d.InventoryItemId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.InventoryItemId = d.InventoryItemId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_InventoryItem([InventoryItemId], [InventoryItemTypeId], [InventoryLocationId], [PartId], [SupplierId], [SerialNumber], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryItemId], [InventoryItemTypeId], [InventoryLocationId], [PartId], [SupplierId], [SerialNumber], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_InventoryItem([InventoryItemId], [InventoryItemTypeId], [InventoryLocationId], [PartId], [SupplierId], [SerialNumber], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryItemId], [InventoryItemTypeId], [InventoryLocationId], [PartId], [SupplierId], [SerialNumber], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND